$ErrorActionPreference = 'Stop'
Write-Host '🚀 Refactor Deployment...' -ForegroundColor Magenta

function Write-JavaFile {
    param($RelPath, $B64)
    $fullPath = Join-Path (Get-Location) $RelPath
    $dir = Split-Path $fullPath -Parent
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    $bytes = [System.Convert]::FromBase64String($B64)
    [System.IO.File]::WriteAllBytes($fullPath, $bytes)
    Write-Host "  OK $RelPath" -ForegroundColor Green
}

Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\model\Customer.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\model\Project.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\model\Sketch.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\repository\CustomerRepository.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\repository\ProjectRepository.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\repository\SketchRepository.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\service\FurnitureRagService.java" -B64 ""
Write-JavaFile -RelPath "src\main\java\com\yourcompany\furniture\controller\FurnitureRagController.java" -B64 ""

Write-Host '✅ Ολα ετοιμα! Τρεχω build...' -ForegroundColor Green
cmd /c 'mvn clean spring-boot:run'